<script>import AuthFrame from '$lib/components/AuthFrame.svelte';let name='';let email='';let password='';let error='';let busy=false;async function submit(){busy=true;error='';const response=await fetch('/api/setup',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({name,email,password})});const data=await response.json();if(!response.ok){error=data.error||'Setup failed';busy=false;return}location.href='/'}</script>
<AuthFrame step="First run · Step 1 of 1" title="Claim this server" description="Create the first owner account. Registration closes permanently after this step."><div class="tag">New installation</div><h2>Owner account</h2><p class="lead">This account can manage deployments, secrets and server access.</p>{#if error}<div class="error">{error}</div>{/if}<form onsubmit={(e)=>{e.preventDefault();submit()}}><label>Full name<input bind:value={name} autocomplete="name" placeholder="Brahim Oulhaj" required/></label><label>Email address<input bind:value={email} type="email" autocomplete="email" placeholder="you@company.com" required/></label><label>Password<input bind:value={password} type="password" autocomplete="new-password" minlength="10" placeholder="At least 10 characters" required/></label><button disabled={busy}>{busy?'Creating owner…':'Create owner account'}<span>→</span></button></form><small class="note">Registration is disabled after the owner is created.</small></AuthFrame>
<style>.tag{display:inline-flex;padding:6px 9px;background:#172017;color:#8bd59a;border:1px solid #28352a;border-radius:5px;font:9px var(--font-mono);text-transform:uppercase;letter-spacing:.08em}h2{font-size:25px;letter-spacing:-.04em;margin:18px 0 6px}.lead{font-size:12px;color:#7e887f;line-height:1.6;margin:0 0 25px}.error{padding:10px 12px;border:1px solid #6c3432;background:#261615;color:#f09490;border-radius:6px;font-size:11px;margin-bottom:16px}form{display:grid;gap:15px}label{display:grid;gap:7px;font-size:10px;font-weight:700;color:#a9b1aa}input{height:43px;background:#111412;border:1px solid #2a302b;border-radius:7px;padding:0 12px;color:#eef2ec;font:12px var(--font-sans);outline:none}input:focus{border-color:#829c43;box-shadow:0 0 0 3px #d8ff7311}button{height:44px;border:0;border-radius:7px;background:#d8ff73;color:#0b0d0c;font:700 11px var(--font-sans);margin-top:5px;display:flex;justify-content:space-between;align-items:center;padding:0 15px}button:disabled{opacity:.6}.note{display:block;color:#586159;font:9px var(--font-mono);margin-top:18px}</style>
